#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

struct Node{
    int lc,rc,sum;
}t[N*4+N*20];

int n,m,a[N],ls[N],len,root[N],tot;
map<int,int> id;

void add(int p,int q,int l,int r,int x){
    if(l==r){
        t[p].sum=t[q].sum+1;
        return;
    }
    t[p].lc=t[q].lc;
    t[p].rc=t[q].rc;
    int mid=l+r>>1;
    if(x<=mid){
        t[p].lc=++tot;
        add(t[p].lc,t[q].lc,l,mid,x);
    }else{
        t[p].rc=++tot;
        add(t[p].rc,t[q].rc,mid+1,r,x);
    }
    t[p].sum=t[t[p].lc].sum+t[t[p].rc].sum;
}

int query(int p,int q,int l,int r,int k){
    if(l==r)
        return ls[l];
    int mid=l+r>>1;
    if(t[t[p].lc].sum-t[t[q].lc].sum>=k)
        return query(t[p].lc,t[q].lc,l,mid,k);
    else
        return query(t[p].rc,t[q].rc,mid+1,r,k-(t[t[p].lc].sum-t[t[q].lc].sum));
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        scanf("%d",&a[i]);
        ls[i]=a[i];
    }
    sort(ls+1,ls+n+1);
    int len=unique(ls+1,ls+n+1)-ls-1;
    for(int i=1;i<=len;i++)
        id[ls[i]]=i;
    root[0]=++tot;
    for(int i=1;i<=n;i++){
        root[i]=++tot;
        add(root[i],root[i-1],1,n,id[a[i]]);
    }
    while(m--){
        int l,r,k;
        scanf("%d%d%d",&l,&r,&k);
        printf("%d\n",query(root[r],root[l-1],1,n,k));
    }
    return 0;
}
